  ('disabled-6f0ba476-moex-00245', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '若中央銀行採取較積極之貨幣政策，對貨幣政策法則（monetary policy rule, MPR）曲線（實質利率為通貨膨脹的函數）與總合需求曲線會產生何種影響？', '["MPR曲線變得更陡直，總合需求曲線變得更平緩", "MPR曲線變得更平緩，總合需求曲線變得更陡直", "MPR曲線與總合需求曲線皆變得更陡直", "MPR曲線與總合需求曲線皆變得更平緩"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
