  ('disabled-6f0ba476-moex-00247', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '假設邊際消費傾向小於 1。根據 IS-LM 與 AD-AS 模型，如果政府消費支 出與稅收等額增加，則在其他條件不變下，下列敘述何者正確？', '["短期均衡實質GDP與名目利率都不變", "短期均衡實質GDP與名目利率都上升", "短期均衡實質GDP與名目利率都下降", "短期均衡一般物價水準上升且名目利率下降"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00248', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '根據莫迪格里尼（FrancoModigliani）的生命循環假說，假設消費者希望每 年的消費皆均等、利率為零，且每年所得皆相同，該名消費者還有 40 年 才退休，生命餘年還有60年。該名消費者之所得邊際消費傾向為何？', '["0.20", "0.40", "0.60", "0.67"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
